from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["support-session-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>God Mode Support Session</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:8px}button,input,textarea,select{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}button.bad{background:var(--bad);color:white}.item{border-left:4px solid var(--ok);padding:9px 10px;background:#081226;border-radius:14px;word-break:break-word}.warn{border-left-color:var(--warn)}.badline{border-left-color:var(--bad)}textarea{width:100%;min-height:90px}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:620px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}}</style></head><body><div class="page"><section class="panel"><h1>God Mode Support Session</h1><p class="muted">Sessão temporária de suporte. Diagnóstico redigido. Ações assistidas só com aprovação no telemóvel.</p><div class="buttons"><button onclick="location.href='/app/install-use-now'" class="dark">Install & Use</button><button onclick="createSession()">Criar sessão</button><button onclick="diagnostics()">Diagnóstico redigido</button><button onclick="dashboard()">Dashboard</button><button onclick="revoke()" class="bad">Revogar sessão</button></div></section><section class="panel"><h2>Sessão</h2><div class="grid"><input id="sessionId" placeholder="support-session-..."/><input id="ttl" value="60"/><select id="mode"><option>assisted_action</option><option>read_only</option><option>diagnostic</option></select></div><textarea id="reason">Temporary support/test session for installed God Mode.</textarea></section><section class="panel"><h2>Propor ação assistida</h2><div class="grid"><input id="actionTitle" value="Export redacted diagnostics"/><select id="actionType"><option>read_diagnostics</option><option>export_redacted_bundle</option><option>create_github_issue_plan</option><option>prepare_pr_plan</option><option>request_screenshot</option><option>run_safe_check_request</option><option>run_command</option><option>write_file</option></select><select id="risk"><option>low</option><option>medium</option><option>high</option></select></div><textarea id="actionReason">Need support diagnostics to debug the installed God Mode.</textarea><button onclick="proposeAction()">Propor ação → popup mobile</button></section><section class="panel"><h2>Sessões / ações</h2><div id="items" class="grid"></div></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){if(x?.support_session?.support_session_id) qs('#sessionId').value=x.support_session.support_session_id; const sessions=x?.support_sessions||x?.dashboard?.support_sessions||[]; const actions=x?.proposed_actions||x?.dashboard?.proposed_actions||[]; qs('#items').innerHTML=[...sessions.slice(-8).map(s=>`<div class="item"><b>${esc(s.status)}</b><br>${esc(s.support_session_id)}<br><span class="muted">expires ${esc(s.expires_at)}</span></div>`),...actions.slice(-8).map(a=>`<div class="item ${a.blocked_by_policy?'badline':'warn'}"><b>${esc(a.status)}</b><br>${esc(a.title)}<br><span class="muted">${esc(a.action_type)} | ${esc(a.permission_request_id||'no gate')}</span></div>`)].join('')}async function createSession(){show(await api('/api/support-session/create',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({ttl_minutes:Number(qs('#ttl').value||60),mode:qs('#mode').value,reason:qs('#reason').value})}))}async function diagnostics(){show(await api('/api/support-session/diagnostics',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({support_session_id:qs('#sessionId').value||null})}))}async function proposeAction(){show(await api('/api/support-session/propose-action',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({support_session_id:qs('#sessionId').value,title:qs('#actionTitle').value,action_type:qs('#actionType').value,reason:qs('#actionReason').value,risk_level:qs('#risk').value,proposed_payload:{source:'support-ui'},rollback_hint:'No automatic rollback required.'})}))}async function revoke(){show(await api('/api/support-session/revoke',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({support_session_id:qs('#sessionId').value})}))}async function dashboard(){show(await api('/api/support-session/dashboard'))}dashboard()</script></body></html>
"""


@router.get('/app/support-session', response_class=HTMLResponse)
async def support_session_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/temporary-support', response_class=HTMLResponse)
async def temporary_support_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
